tool_input.code:
import pandas as pd
import ast
from collections import Counter

# Load the new CSV with docket number RM26-4-000 only
df = pd.read_csv('/work/ferc_search_20260617_231946.csv')

# Count filings per author, treating joint filings carefully
# For joint filings, each author is counted as having filed that document
author_filing_counts = Counter()
entity_filings = {}

for idx, row in df.iterrows():
    affiliations = ast.literal_eval(row['affiliations'])
    filing_authors = set()
    for aff in affiliations:
        if aff.startswith('AUTHOR:'):
            author = aff.replace('AUTHOR:', '').strip()
            filing_authors.add(author)

    for author in filing_authors:
        author_filing_counts[author] += 1
        if author not in entity_filings:
            entity_filings[author] = []
        entity_filings[author].append((row['filed_date'], row['title']))

# Show all entities with more than 1 filing
print("All entities with more than 1 filing in RM26-4-000:")
for author, count in author_filing_counts.most_common():
    if count > 1:
        print(f"\n{count}: {author}")
        for d, t in entity_filings[author]:
            print(f"   - {d}: {t}")

print("\n" + "="*80)
print("Top 3 entities with most filings:")
top3 = author_filing_counts.most_common(3)
for i, (author, count) in enumerate(top3, 1):
    print(f"{i}. {author}: {count} filings")

